const ASCII_CHARS = "@#S%?*+;:,. ";
const ASCII_CHARS_BW = ASCII_CHARS.split('').reverse().join('');
const mapScale = (ASCII_CHARS.length - 1) / 255;

let bitCanvas, bitCtx;

self.onmessage = async (e) => {
    const { 
      bitmap,
      width,
      height, 
      isColor,
      fontSize,
    } = e.data;
    
    
    if (!bitCanvas) {
        bitCanvas = new OffscreenCanvas(width * fontSize, height * fontSize);
        bitCtx = bitCanvas.getContext("2d");
        bitCtx.textBaseline = "top";
        bitCtx.font = `${fontSize}px monospace`;
    }

    bitCanvas.width = width * fontSize;
    bitCanvas.height = height * fontSize;

    bitCtx.fillStyle = "#000";
    bitCtx.fillRect(0, 0, bitCanvas.width, bitCanvas.height);

    const tmpCanvas = new OffscreenCanvas(bitmap.width, bitmap.height);
    const tmpCtx = tmpCanvas.getContext("2d");
    tmpCanvas.width = bitmap.width;
    tmpCanvas.height = bitmap.height;
    tmpCtx.drawImage(bitmap, 0, 0);



    const srcW = bitmap.width;
    const srcH = bitmap.height;

    const dstW = width;
    const dstH = height;

    const srcAspect = srcW / srcH;
    const dstAspect = width / height;

    let dw, dh, offsetX, offsetY;

    if (srcAspect > dstAspect) {
        dw = dstW;
        dh = dw / srcAspect;
        offsetX = 0;
        offsetY = (dstH - dh) / 2;
    } else {
        dh = dstH;
        dw = dh * srcAspect;
        offsetY = 0;
        offsetX = (dstW - dw) / 2;
    }

    const imgData = tmpCtx.getImageData(0, 0, srcW, srcH).data;
    const chars = isColor ? ASCII_CHARS : ASCII_CHARS_BW;

    for (let y = 0; y < dstH; y++) {
        for (let x = 0; x < dstW; x++) {
          let r = 0, g = 0, b = 0;

      if (x >= offsetX && x < offsetX + dw && y >= offsetY && y < offsetY + dh) {
        const u = (x - offsetX) / dw;
        const v = (y - offsetY) / dh;

        const srcX = Math.min(srcW - 1, Math.floor(u * srcW));
        const srcY = Math.min(srcH - 1, Math.floor(v * srcH));

        const idx = (srcY * srcW + srcX) * 4;
        r = srcData[idx];
        g = srcData[idx + 1];
        b = srcData[idx + 2];
      }

          const brightness = Math.floor((r + g + b) / 3);
          const index = Math.floor(brightness * mapScale);
          const char = chars[index];

          if (isColor) {
            bitCtx.fillStyle = `rgb(${r}, ${g}, ${b})`;
          } else {
            bitCtx.fillStyle = "#fff";
          }

          bitCtx.fillText(
            char, 
            x * fontSize,
            y * fontSize
        );
      };
    };

    const result = bitCanvas.transferToImageBitmap();
    self.postMessage(result, [result]);
};
